find:
return axios(AUTH_GRAPHQL_URL, options)
  .then((r) => r?.data?.data?.me)
  .catch((e) =>
    log.error("[core]", "[AUTH] Fetch user error", e?.response?.data?.errors)
  );

replace:
return axios(AUTH_GRAPHQL_URL, options)
  .then((r) => {
    const _me = r?.data?.data?.me;
    if (_me && Array.isArray(_me.roles) && !_me.roles.some((_r) => _r.code === "PRO_SUBSCRIBER")) {
      _me.roles.push({ code: "PRO_SUBSCRIBER" });
    }
    return _me;
  })
  .catch((e) =>
    log.error("[core]", "[AUTH] Fetch user error", e?.response?.data?.errors)
  );
